import React from "react";
import { BrowserRouter, Routes, Route } from "react-router-dom";
import Store from "./pages/Store";

export default function App() {
    return ( <
        BrowserRouter >
        <
        Routes >
        <
        Route path = "/store/:phone"
        element = { < Store / > }
        /> <
        Route path = "*"
        element = { < div style = {
                { textAlign: 'center', marginTop: 40 } } > < h1 > Welcome to ArewaMarket < /h1><p>To view a trader's store, use their unique link.</p > < /div>} / >
            <
            /Routes> <
            /BrowserRouter>
        );
    }
